#include <bits/stdc++.h>
using namespace std;
int n,k,l,r,cnt;
const int N=500005;
int a[N],s[N],st[N][30];
struct node
{
    int x,l,r;
};
priority_queue<int,vector<int>,greater<int> > ans;
queue<node> q;
void prepare()
{
    for(int j=1;(1<<j)<=n;j++)
    {
        for(int i=1;i<=n;i++)
        {
            int t=i+(1<<j)-1;
            if(t>n) continue;
            int x=st[i][j-1],y=st[i+(1<<(j-1))][j-1];
            if(s[x]>s[y]) st[i][j]=x;
            else st[i][j]=y;
        }
    }
}
int RMQ(int x,int y)
{
    int len=y-x+1;
    int len2=log2(len);
    int x2=st[x][len2],y2=st[y-(1<<len2)+1][len2];
    if(s[x2]>s[y2])  return x2;
    return y2;
}
int main()
{
	cin>>n>>k>>l>>r;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        s[i]=s[i-1]+a[i];
        st[i][0]=i;
    }
    prepare(); 
    for(int i=1;i<=n;i++)
    {
        int left=i+l-1,right=i+r-1;
        if(left>n) break;
        right=min(right,n);
        node t;
        t.x=i,t.l=left,t.r=right;
        q.push(t);
    }
    while(!q.empty())
    {
        node t=q.front();
        q.pop();
        int id=RMQ(t.l,t.r);
        int num=s[id]-s[t.x-1];
        if(cnt<k)
        {
            cnt++;
            ans.push(num);
            node t2;
            if(id>t.l)
            {
                t2.x=t.x,t2.l=t.l,t2.r=id-1;
                q.push(t2);
            }
            if(id<t.r)
            {
                t2.x=t.x,t2.l=id+1,t2.r=t.r;
                q.push(t2);
            }
        }
        else if(num>ans.top())
        {
            ans.pop();
            ans.push(num);
            node t2;
            if(id>t.l)
            {
                t2.x=t.x,t2.l=t.l,t2.r=id-1;
                q.push(t2);
            }
            if(id<t.r)
            {
                t2.x=t.x,t2.l=id+1,t2.r=t.r;
                q.push(t2);
            }
        }
    }
    long long sum=0;
    while(cnt--)
    {
        sum+=ans.top();
        ans.pop();
    }
    cout<<sum;
	return 0;
}
